mapper.update:
INSERT INTO TB_BBS_PST (
    BRD_CD
  , PST_CD
  , PST_NM
  , PST_CNTS
  , PST_LVL
  , ROT_PST_CD
  , UPR_PST_CD
  , NOTICE_YN
  , RGT_USR_CD
  , RGT_USR_NM

  , RGT_EMAIL


  , RGT_PHONE


  , SECRET_YN


  , SECRET_PWD

  , RGT_DTM
  , ATCH_FILE_KEY
  , ATCH_FILE_TYPE
  , VIEW_CNT
  , IDX
  , THUMB_URL
  , USE_YN
  , DEL_YN
  , CRE_USR_CD
  , CRE_DTM
  , UPD_USR_CD
  , UPD_DTM
) VALUES (
    #{brdCd}
  , #{pstCd}
  , #{pstNm}
  , #{pstCnts}
  , IFNULL(#{pstLvl}, 0)
  , #{rotPstCd}
  , #{uprPstCd}
  , IFNULL(#{noticeYn}, 'N')
  , #{ssnUsrCd}
  , #{rgtUsrNm}

  , #{rgtEmail}


  , F_COM_ENCRYPT(#{rgtPhone}, #{encryptKey})


  , #{secretYn}


  , F_COM_ENCRYPT(TRIM(#{secretPwd}), #{encryptKey})

  , SYSDATE()
  , #{atchFileKey}
  , 0
  , 0
  , (SELECT IFNULL(MAX(T.IDX), 0) + 1 FROM TB_BBS_PST T WHERE T.BRD_CD = #{brdCd})
  , #{thumbUrl}
  , 'Y'
  , 'N'
  , #{ssnUsrCd}
  , SYSDATE()
  , #{ssnUsrCd}
  , SYSDATE()
)
ON DUPLICATE KEY UPDATE
    PST_NM        = #{pstNm}
  , PST_CNTS      = #{pstCnts}
  , THUMB_URL 	= #{thumbUrl}
  , NOTICE_YN     = IFNULL(#{noticeYn}, 'N')

  , RGT_EMAIL     = #{rgtEmail}


  , RGT_PHONE     = F_COM_ENCRYPT(#{rgtPhone}, #{encryptKey})


  , SECRET_PWD    = F_COM_ENCRYPT(TRIM(#{secretPwd}), #{encryptKey})

  , UPD_USR_CD    = #{ssnUsrCd}
  , UPD_DTM       = SYSDATE()

  , ATCH_FILE_KEY = #{atchFileKey}

UPDATE TB_BBS_PST
   SET VIEW_CNT = IFNULL(VIEW_CNT, 0) + 1
 WHERE BRD_CD = #{brdCd}
   AND PST_CD = #{pstCd}
   AND DEL_YN = 'N'

mapper.select:
SELECT COUNT(*)
  FROM TB_BBS_PST
 WHERE BRD_CD = #{brdCd}
   AND PST_CD = #{pstCd}
   AND DEL_YN = 'N'
   AND SECRET_PWD = F_COM_ENCRYPT(#{secretPwd}, #{encryptKey})

mapper.update:
UPDATE TB_BBS_PST
   SET DEL_YN = 'Y'
     , USE_YN = 'N'
     , UPD_USR_CD = #{ssnUsrCd}
     , UPD_DTM = SYSDATE()
 WHERE BRD_CD = #{brdCd}
   AND PST_CD = #{pstCd}
   AND DEL_YN = 'N'
